head.b:skin:
/*------------------------------------------------------------
PREMIUM PRO NEWS MASTER VARIABLE SYSTEM
------------------------------------------------------------*/
:root {
    --primary-gradient: linear-gradient(135deg, #ff1e56 0%, #ffac41 50%, #3232ff 100%);
    --neon-glow: 0 0 25px rgba(255, 30, 86, 0.3);
    --dark-bg: #030712;
    --dark-card: #0f172a;
    --light-bg: #f8fafc;
    --light-card: #ffffff;
    --text-main: #0f172a;
    --text-muted: #475569;
    --accent-color: #ff1e56;
    --font-global: 'Plus Jakarta Sans', 'Noto Sans Devanagari', sans-serif;
    --radius-mega: 18px;
    --shadow-mega: 0 25px 50px -12px rgba(15, 23, 42, 0.06);
    --transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

body.dark-mode {
    --light-bg: var(--dark-bg);
    --light-card: var(--dark-card);
    --text-main: #f1f5f9;
    --text-muted: #94a3b8;
    --shadow-mega: 0 30px 60px rgba(0, 0, 0, 0.5);
}

/* Core Reset Definitions */
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: var(--font-global); background-color: var(--light-bg); color: var(--text-main); transition: var(--transition); overflow-x: hidden; }
a { color: inherit; text-decoration: none; transition: var(--transition); }
img { max-width: 100%; height: auto; display: block; border-radius: 12px; }

#progress-bar { position: fixed; top: 0; left: 0; width: 0%; height: 5px; background: var(--primary-gradient); z-index: 100000; }
.container { max-width: 1360px; margin: 0 auto; padding: 0 24px; }

/* Top Live Running Header Ticker */
.top-bar { background: #090d16; color: #fff; padding: 14px 0; font-size: 13px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.ticker-wrap { display: flex; align-items: center; justify-content: space-between; gap: 20px; }
.ticker-box { display: flex; align-items: center; overflow: hidden; width: 80%; }
.ticker-title { background: var(--primary-gradient); padding: 6px 16px; font-weight: 900; border-radius: 8px; margin-right: 20px; white-space: nowrap; font-size: 12px; box-shadow: var(--neon-glow); animation: pulse 2s infinite; }
.ticker-content { display: inline-block; white-space: nowrap; animation: ticker-live 30s linear infinite; color: #e2e8f0; font-weight: 700; }
@keyframes ticker-live { 0% { transform: translate3d(100%, 0, 0); } 100% { transform: translate3d(-100%, 0, 0); } }

/* Ultra Luxury Sticky Header Branding */
header { background: rgba(255, 255, 255, 0.85); backdrop-filter: blur(25px); -webkit-backdrop-filter: blur(25px); position: sticky; top: 0; z-index: 9999; box-shadow: 0 4px 30px rgba(0,0,0,0.03); border-bottom: 1px solid rgba(0,0,0,0.05); padding: 20px 0; }
body.dark-mode header { background: rgba(15, 23, 42, 0.85); border-bottom: 1px solid rgba(255,255,255,0.06); }
.header-inner { display: flex; flex-direction: column; align-items: center; gap: 24px; }
@media(min-width: 992px) { .header-inner { flex-direction: row; justify-content: space-between; } }

.logo-branding { position: relative; padding: 8px 28px; text-align: center; background: rgba(255, 30, 86, 0.03); border-radius: 16px; border: 1px solid rgba(255, 30, 86, 0.08); }
.logo-branding h1 { font-size: 46px; font-weight: 900; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; letter-spacing: -1.5px; text-transform: uppercase; line-height: 1.1; filter: drop-shadow(0 2px 10px rgba(255,30,86,0.2)); }
.logo-sub { display: block; font-size: 11px; font-weight: 900; color: var(--text-muted); letter-spacing: 6px; text-transform: uppercase; margin-top: 5px; }

nav ul { display: flex; list-style: none; gap: 32px; flex-wrap: wrap; justify-content: center; }
nav ul li a { font-weight: 800; font-size: 16px; color: var(--text-main); padding: 8px 0; position: relative; display: flex; align-items: center; gap: 8px; }
nav ul li a::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 4px; background: var(--primary-gradient); transition: var(--transition); border-radius: 4px; }
nav ul li a:hover::after { width: 100%; }

.nav-actions { display: flex; align-items: center; gap: 15px; }
.mode-btn { width: 46px; height: 46px; border-radius: 14px; background: var(--light-bg); display: flex; align-items: center; justify-content: center; cursor: pointer; border: 1px solid rgba(0,0,0,0.05); transition: var(--transition); color: var(--text-main); }
.mode-btn:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-3px) rotate(15deg); box-shadow: var(--neon-glow); }

/* Massive Premium Featured Banner System */
.featured-hero-grid { display: grid; grid-template-columns: 1fr; gap: 24px; margin-top: 35px; }
@media(min-width: 768px) { .featured-hero-grid { grid-template-columns: 2fr 1fr; } }
.hero-banner-main { position: relative; height: 420px; border-radius: var(--radius-mega); overflow: hidden; box-shadow: var(--shadow-mega); }
.hero-banner-main img { width: 100%; height: 100%; object-fit: cover; }
.hero-overlay { position: absolute; inset: 0; background: linear-gradient(to top, rgba(3,7,18,0.95) 0%, rgba(3,7,18,0.4) 60%, transparent 100%); display: flex; flex-direction: column; justify-content: flex-end; padding: 40px; }
.hero-title { color: #fff; font-size: 28px; font-weight: 900; line-height: 1.3; margin-top: 10px; }

/* Structural Split Grid Engine */
.main-wrapper { display: grid; grid-template-columns: 1fr; gap: 45px; margin-top: 45px; }
@media(min-width: 992px) { .main-wrapper { grid-template-columns: 2.4fr 1fr; } }

/* Modern Chronological Multi-Grid Cards Layout */
.posts-grid { display: grid; grid-template-columns: 1fr; gap: 35px; }
@media(min-width: 680px) { .posts-grid { grid-template-columns: 1fr 1fr; } }

.card { background: var(--light-card); border-radius: var(--radius-mega); overflow: hidden; box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); display: flex; flex-direction: column; height: 100%; transition: var(--transition); }
.card:hover { transform: translateY(-10px); box-shadow: 0 35px 70px rgba(255, 30, 86, 0.15); border-color: rgba(255, 30, 86, 0.25); }
.card-thumb { height: 250px; background: #0f172a; position: relative; overflow: hidden; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: var(--transition); }
.card:hover .card-thumb img { transform: scale(1.08); }

.badge { position: absolute; top: 18px; left: 18px; background: var(--primary-gradient); color: #fff; padding: 6px 16px; font-size: 11px; font-weight: 900; border-radius: 8px; box-shadow: var(--neon-glow); text-transform: uppercase; letter-spacing: 0.5px; }
.card-content { padding: 28px; flex-grow: 1; display: flex; flex-direction: column; justify-content: space-between; }
.card-meta { font-size: 13.5px; color: var(--text-muted); margin-bottom: 14px; display: flex; gap: 16px; font-weight: 700; }
.card-meta i { color: var(--accent-color); }
.card-title { font-size: 22px; font-weight: 800; line-height: 1.4; margin-bottom: 14px; color: var(--text-main); transition: var(--transition); }
.card-title a:hover { color: var(--accent-color); }
.card-text { font-size: 14.5px; color: var(--text-muted); line-height: 1.7; margin-bottom: 24px; }
.read-btn { font-weight: 800; font-size: 14.5px; color: var(--accent-color); display: inline-flex; align-items: center; gap: 8px; }

/* Single Premium Post Typography Hierarchy */
.post-body-container { background: var(--light-card); padding: 45px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); }
.post-main-title { font-size: 38px; font-weight: 900; line-height: 1.35; margin-bottom: 24px; color: var(--text-main); letter-spacing: -0.5px; }
.breadcrumb-nav { display: flex; gap: 8px; font-size: 14px; color: var(--text-muted); margin-bottom: 28px; font-weight: 700; }
.post-content-inner { font-size: 17.5px; line-height: 1.95; color: var(--text-main); }
.post-content-inner p { margin-bottom: 24px; }
.post-content-inner h2, .post-content-inner h3 { font-size: 28px; font-weight: 800; margin: 40px 0 20px; border-left: 6px solid var(--accent-color); padding-left: 18px; background: linear-gradient(90deg, rgba(255,30,86,0.04), transparent); padding-vertical: 6px; }

.share-container { display: flex; gap: 14px; margin: 40px 0; flex-wrap: wrap; }
.share-btn { padding: 14px 24px; border-radius: 12px; color: #fff; font-size: 14.5px; font-weight: 800; display: flex; align-items: center; gap: 10px; box-shadow: 0 5px 20px rgba(0,0,0,0.05); }
.share-fb { background: #1877f2; }
.share-wa { background: #25d366; }

/* Hot Trend Now Highlight Block Grid */
.hot-trend-box { margin-top: 50px; background: var(--light-card); border-radius: var(--radius-mega); padding: 35px; box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); position: relative; }
.hot-trend-box::before { content: ''; position: absolute; top: 0; left: 0; width: 6px; height: 100%; background: var(--primary-gradient); border-radius: 18px 0 0 18px; }
.trend-head { display: flex; align-items: center; gap: 14px; margin-bottom: 28px; }
.trend-head h3 { font-size: 20px; font-weight: 900; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; text-transform: uppercase; }
.trend-icon-flash { background: var(--primary-gradient); color: #fff; width: 36px; height: 36px; border-radius: 10px; display: flex; align-items: center; justify-content: center; font-size: 16px; box-shadow: var(--neon-glow); }

.trend-grid { display: grid; grid-template-columns: 1fr; gap: 24px; }
@media(min-width: 600px) { .trend-grid { grid-template-columns: 1fr 1fr; } }
.trend-item { display: flex; gap: 18px; align-items: center; background: var(--light-bg); padding: 18px; border-radius: 16px; border: 1px solid rgba(0,0,0,0.02); transition: var(--transition); }
.trend-item:hover { transform: scale(1.03); background: #fff; box-shadow: 0 20px 40px rgba(0,0,0,0.06); border-color: rgba(255, 30, 86, 0.25); }
.trend-img-holder { width: 85px; height: 85px; border-radius: 12px; overflow: hidden; flex-shrink: 0; background: #cbd5e1; }
.trend-img-holder img { width: 100%; height: 100%; object-fit: cover; }
.trend-info h4 { font-size: 15px; font-weight: 800; line-height: 1.4; color: var(--text-main); margin-bottom: 6px; }
.trend-meta { font-size: 12.5px; color: var(--text-muted); font-weight: 700; }

/* Ultra Advanced Sidebar Architecture Panels */
.sidebar-pane { display: flex; flex-direction: column; gap: 40px; }
.block-widget { background: var(--light-card); padding: 32px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); }
.block-title { font-size: 16.5px; font-weight: 900; text-transform: uppercase; margin-bottom: 26px; position: relative; padding-bottom: 14px; letter-spacing: 0.5px; color: var(--text-main); border-bottom: 2px solid rgba(0,0,0,0.04); }
.block-title::after { content: ''; position: absolute; bottom: -2px; left: 0; width: 55px; height: 2px; background: var(--primary-gradient); }

/* Advanced Analytics Graphic Box Counters */
.analytics-box { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-top: 10px; }
.analytic-card { background: var(--light-bg); padding: 18px; border-radius: 14px; text-align: center; border: 1px solid rgba(0,0,0,0.02); }
.analytic-num { font-size: 22px; font-weight: 900; color: var(--accent-color); margin-bottom: 4px; }
.analytic-label { font-size: 12px; font-weight: 700; color: var(--text-muted); text-transform: uppercase; }

/* Native Core Element Input Styling */
.search-input-group form { display: flex; gap: 10px; width: 100%; }
.search-field { flex-grow: 1; padding: 15px 20px; border: 1px solid rgba(0,0,0,0.08); border-radius: 14px; background: var(--light-bg); color: var(--text-main); font-weight: 600; outline: none; transition: var(--transition); }
.search-field:focus { border-color: var(--accent-color); background: #fff; box-shadow: 0 0 0 4px rgba(255,30,86,0.1); }
.search-go-btn { background: var(--primary-gradient); color: #fff; border: none; padding: 0 24px; border-radius: 14px; font-weight: 900; cursor: pointer; box-shadow: var(--neon-glow); }

.tag-cloud-list { display: flex; flex-wrap: wrap; gap: 10px; list-style: none; }
.tag-cloud-list li a { display: block; background: var(--light-bg); padding: 8px 18px; font-size: 14px; font-weight: 700; border-radius: 12px; border: 1px solid rgba(0,0,0,0.02); }
.tag-cloud-list li a:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-3px); box-shadow: var(--neon-glow); }

.bio-avatar { width: 100px; height: 100px; border-radius: 50%; margin: 0 auto 18px; border: 4px solid #fff; box-shadow: 0 0 0 3px var(--accent-color); object-fit: cover; display: block; }
.bio-title { font-size: 19px; font-weight: 800; margin-bottom: 10px; text-align: center; }
.bio-desc { font-size: 14.5px; color: var(--text-muted); line-height: 1.6; text-align: center; margin-bottom: 18px; }
.bio-more-link { display: block; text-align: center; font-size: 13px; font-weight: 800; color: var(--accent-color); text-transform: uppercase; }

/* Massive Professional Multi-Row Footer */
footer { background: #02050b; color: #94a3b8; padding: 90px 0 45px; margin-top: 100px; border-top: 4px solid rgba(255, 30, 86, 0.3); }
.footer-grid-container { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 50px; margin-bottom: 55px; }
.footer-widget-box h3 { color: #fff; margin-bottom: 26px; font-size: 22px; font-weight: 900; position: relative; }
.footer-widget-box h3::after { content: ''; position: absolute; bottom: -8px; left: 0; width: 50px; height: 3px; background: var(--primary-gradient); }
.footer-widget-box p { font-size: 15px; line-height: 1.8; }
.footer-links-menu { list-style: none; }
.footer-links-menu li { margin-bottom: 14px; font-size: 15px; font-weight: 700; }
.footer-links-menu li a:hover { color: #fff; padding-left: 8px; }

.footer-legal-base { border-top: 1px solid rgba(255,255,255,0.06); padding-top: 35px; text-align: center; font-size: 15px; font-weight: 700; color: #475569; }
.footer-legal-base a { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 900; }

#back-to-top { position: fixed; bottom: 35px; right: 35px; background: var(--primary-gradient); color: #fff; width: 52px; height: 52px; border-radius: 16px; display: none; align-items: center; justify-content: center; cursor: pointer; z-index: 99999; box-shadow: var(--neon-glow); border: none; transition: var(--transition); }
#back-to-top:hover { transform: translateY(-6px); }

body.script:
//
// 1. Theme State System Toggle Controller
const actionButtonElement = document.getElementById('dark-mode-engine-btn');
const visualIconElement = actionButtonElement.querySelector('i');
actionButtonElement.addEventListener('click', () => {
    document.body.classList.toggle('dark-mode');
    if(document.body.classList.contains('dark-mode')) {
        visualIconElement.className = 'fas fa-sun';
    } else {
        visualIconElement.className = 'fas fa-moon';
    }
});

// 2. Reading Percentage Vector Scroller Component Tracker
window.addEventListener('scroll', () => {
    const documentScrollTop = document.body.scrollTop || document.documentElement.scrollTop;
    const absoluteScrollHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const progressRatioValue = (documentScrollTop / absoluteScrollHeight) * 100;
    document.getElementById('progress-bar').style.width = progressRatioValue + '%';

    const triggerTopBtn = document.getElementById('back-to-top');
    if(documentScrollTop > 450) { triggerTopBtn.style.display = 'flex'; } else { triggerTopBtn.style.display = 'none'; }
});

document.getElementById('back-to-top').addEventListener('click', () => {
    window.scrollTo({top: 0, behavior: 'smooth'});
});

// 3. Indian Language Automatic Clock Output System
document.getElementById('live-clock-system').innerText = new Date().toLocaleDateString('hi-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
//
